const subject = $json.subject || '';
if (!/YouTube Crypto Digest/i.test(subject)) {
  return null; // not a reply to our digest, stop the pipeline here
}

const text = $json.textPlain || '';
const lines = text.split('\n');

// Find where quoting starts (Gmail-style "On ... wrote:" or lines starting with '>')
let boundary = lines.length;
for (let i = 0; i < lines.length; i++) {
  const l = lines[i].trim();
  if (/^On .+wrote:$/.test(l) || l.startsWith('>')) {
    boundary = i;
    break;
  }
}

const replyBody = lines.slice(0, boundary).join('\n').trim();
const quoted = lines.slice(boundary).map(l => l.replace(/^>\s?/, '')).join('\n');

const numMatch = replyBody.match(/\b([1-5])\b/);
const selectedNum = numMatch ? numMatch[1] : null;

// Parse numbered video list from the quoted original digest: "N. Title (Channel)" then a URL line
const videoMap = {};
const qLines = quoted.split('\n');
for (let i = 0; i < qLines.length; i++) {
  const m = qLines[i].match(/^\s*(\d+)\.\s+(.+)$/);
  if (m) {
    const num = m[1];
    const title = m[2].trim();
    let url = null;
    for (let j = i + 1; j < qLines.length && j < i + 3; j++) {
      const urlMatch = qLines[j].match(/(https?:\/\/\S+)/);
      if (urlMatch) { url = urlMatch[1]; break; }
    }
    videoMap[num] = { title, url };
  }
}

if (!selectedNum || !videoMap[selectedNum] || !videoMap[selectedNum].url) {
  return {
    json: {
      error: 'Could not determine which video was selected',
      selectedNumber: selectedNum,
      videoMap,
      replyBody,
      rawTextPlain: text,
    }
  };
}

return {
  json: {
    selectedNumber: selectedNum,
    selectedTitle: videoMap[selectedNum].title,
    selectedUrl: videoMap[selectedNum].url,
    videoMap,
    replyBody,
  }
};

const vtt = $json.stdout || '';
const rawLines = vtt.split('\n');
const textLines = [];
for (let line of rawLines) {
  line = line.trim();
  if (!line) continue;
  if (line.startsWith('WEBVTT') || line.startsWith('Kind:') || line.startsWith('Language:')) continue;
  if (line.includes('-->')) continue;
  if (/^\d+$/.test(line)) continue;
  line = line.replace(/<[^>]+>/g, '');
  textLines.push(line);
}
const deduped = [];
for (const l of textLines) {
  if (deduped.length === 0 || deduped[deduped.length - 1] !== l) deduped.push(l);
}
const transcript = deduped.join(' ').slice(0, 12000);

return {
  json: {
    transcript,
    videoTitle: $('Parse Reply & Select Video').item.json.selectedTitle,
    videoUrl: $('Parse Reply & Select Video').item.json.selectedUrl,
  }
};

