const raw = $json.choices[0].message.content;
let parsed;
try {
  const cleaned = raw.trim().replace(/^```json\n?/, '').replace(/```$/, '');
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    title: 'Draft: ' + $('Clean Transcript').item.json.videoTitle,
    content: raw,
  };
}
return { json: parsed };
